import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        // Allocate buffer dynamically based on input size
        byte[] buffer = new byte[input.length()];

        // Copy input into buffer using proper length and encoding
        System.arraycopy(input.getBytes(), 0, buffer, 0, Math.min(input.length(), buffer.length));

        System.out.println("Input copied into buffer successfully.");
    }
}

